const handler = (input) => {
  let score = 100; // base

  // Vintage scoring
  if (input.cibilVintageMonths >= 60) score += 30;
  else if (input.cibilVintageMonths >= 24) score += 15;
  else if (input.cibilVintageMonths >= 13) score += 5;
  else if (input.cibilVintageMonths <= 6) score -= 30;

  // DPD penalties
  if (input.dpd30Last6Months > 0) score -= 20;
  if (input.dpd60Last12Months > 0) score -= 25;

  // Enquiry penalties
  if (input.enquiriesLast30Days > 3) score -= 20;
  else if (input.enquiriesLast30Days > 1) score -= 10;
  if (input.enquiriesLast90Days > 6) score -= 15;

  // Credit utilisation
  if (input.creditUtilisationRatio < 0.30) score += 20;
  else if (input.creditUtilisationRatio > 0.80) score -= 25;
  else if (input.creditUtilisationRatio > 0.60) score -= 10;

  // Unsecured/Secured ratio
  if (input.unsecuredToSecuredRatio < 1.0) score += 15;
  else if (input.unsecuredToSecuredRatio > 4.0) score -= 20;
  else if (input.unsecuredToSecuredRatio > 2.0) score -= 10;

  // Unsecured trade lines
  if (input.unsecuredTradeLines > 4) score -= 15;

  // Oldest trade line
  if (input.oldestTradeLineAgeMonths >= 60) score += 15;

  return { bureauBehaviour: Math.max(0, Math.min(200, score)) };
}

const handler = (input) => {
  let score = 60; // base

  // Income band scoring
  if (input.netMonthlySalary >= 200000) score += 50;
  else if (input.netMonthlySalary >= 75000) score += 35;
  else if (input.netMonthlySalary >= 35000) score += 20;
  else if (input.netMonthlySalary >= 20000) score += 5;

  // FOIR scoring
  if (input.foirPostLoan <= 0.30) score += 30;
  else if (input.foirPostLoan <= 0.45) score += 20;
  else if (input.foirPostLoan <= 0.55) score += 10;
  else if (input.foirPostLoan > 0.60) score -= 20;

  // Income verification bonus
  if (input.incomeVerified) score += 10;

  return { incomeFoir: Math.max(0, Math.min(150, score)) };
}

const handler = (input) => {
  let score = 80; // base

  // R-ALT-01: Salary SMS consistency
  if (input.salaryCreditMonthsLast6 >= 6) score += 20;
  else if (input.salaryCreditMonthsLast6 >= 4) score += 5;
  else score -= 20;

  // R-ALT-02: WhatsApp vintage
  if (input.whatsappVintageMonths >= 24) score += 10;
  else if (input.whatsappVintageMonths < 6) score -= 5;

  // R-ALT-03: Investment app
  if (input.hasInvestmentApp) score += 10;

  // R-ALT-04: Lending app count
  if (input.lendingAppsCount === 0) score += 5;
  else if (input.lendingAppsCount > 3) score -= 30;
  else if (input.lendingAppsCount > 1) score -= 10;

  // R-ALT-05: UPI inflow vs income
  if (input.upiInflowVsIncomeRatio >= 0.80) score += 15;
  else if (input.upiInflowVsIncomeRatio < 0.40) score -= 15;

  // R-ALT-06: Active SIP
  if (input.hasActiveSip) score += 15;

  // R-ALT-07: Utility payments
  if (input.utilityPaymentCount >= 12) score += 10;
  else if (input.utilityPaymentCount <= 2) score -= 20;

  // R-ALT-08: Mobile number vintage
  if (input.mobileNumberVintageMonths >= 36) score += 15;
  else if (input.mobileNumberVintageMonths < 12) score -= 25;

  // R-ALT-09: Bank balance trend
  if (input.avgBalance6MonthTrend === 'RISING') score += 10;
  else if (input.avgBalance6MonthTrend === 'DECLINING') score -= 15;

  // R-ALT-10: Location stability
  if (input.homeLocationStable) score += 10;
  else score -= 30;

  return { alternateBehavioural: Math.max(0, Math.min(200, score)) };
}

const handler = (input) => {
  let score = 50; // start max, deduct

  // Device re-use
  if (input.sameDeviceApplicationCount7Days > 3) score -= 30;
  else if (input.sameDeviceApplicationCount7Days > 1) score -= 10;

  // Mobile fraud flag
  if (input.mobileFraudFlag) score -= 40;

  // Location velocity
  if (input.locationVelocityFlag) score -= 20;

  return { fraudRisk: Math.max(0, Math.min(50, score)) };
}

const handler = (input) => {
  const total = (input.bureauScore || 0)
    + (input.bureauBehaviour || 0)
    + (input.incomeFoir || 0)
    + ((input.employerBaseScore || 0) + (input.tenureBonus || 0))
    + (input.alternateBehavioural || 0)
    + (input.fraudRisk || 0);

  let scoreBand;
  if (total < 400) scoreBand = 'DECLINE';
  else if (total < 500) scoreBand = '400-499';
  else if (total < 600) scoreBand = '500-599';
  else if (total < 700) scoreBand = '600-699';
  else if (total < 800) scoreBand = '700-799';
  else scoreBand = '800+';

  return { totalScore: Math.min(1000, total), scoreBand };
}
